+fn http2_app_path_rejects_non_empty_settings_ack_while_reading_body() {
+    let app = App::builder()
+        .post(
+            "/",
+            |_ctx: &RequestContext, _req: &mut Request| async move {
+                Response::ok().body(ResponseBody::Bytes(b"app-path-ok".to_vec()))
+            },
+        )
+        .build();
+
